"use strict";parserFactory.register("yeduge.com",()=>new YedugeParser);class YedugeParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".chapter-list a")].map(YedugeParser.linkToChapter)}static linkToChapter(e){let t=e.textContent.trim(),r=!t.endsWith("VIP");return t.endsWith("VIP")?t=t.slice(0,-3).trim():t.endsWith("免费")&&(t=t.slice(0,-2).trim()),{sourceUrl:e.href,title:t,isIncludeable:r}}findContent(e){return e.querySelector(".content")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"lock"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector(".title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".cover")}extractLanguage(e){return e.querySelector("html").getAttribute("lang")}extractTitleImpl(e){return e.querySelector(".info > h1")}extractAuthor(e){let t=e.querySelector(".info > p:nth-child(2)");return t?.textContent.replace("作者：","").trim()??super.extractAuthor(e)}extractSubject(e){return[...e.querySelectorAll(".info > p:nth-child(4) a"),...e.querySelectorAll(".info > p:nth-child(5) a")].map(e=>e.textContent).join(", ")}extractDescription(e){return e.querySelector(".desc").textContent.trim()}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".novel")]}}